// Foot IK — set IK targets from traces in AnimInstance
void UMyAnimInstance::NativeUpdateAnimation(float DeltaSeconds) {
    Super::NativeUpdateAnimation(DeltaSeconds);
    APawn* Pawn = TryGetPawnOwner();
    if (!Pawn) return;

    // Trace from each foot bone to find ground
    USkeletalMeshComponent* Mesh = Pawn->FindComponentByClass<USkeletalMeshComponent>();
    if (!Mesh) return;

    FVector LeftFootLoc = Mesh->GetSocketLocation(TEXT("foot_l"));
    FVector RightFootLoc = Mesh->GetSocketLocation(TEXT("foot_r"));

    // Trace down from each foot
    FHitResult LeftHit, RightHit;
    FVector TraceStart, TraceEnd;

    TraceStart = LeftFootLoc + FVector(0, 0, 50.f);
    TraceEnd = LeftFootLoc - FVector(0, 0, 100.f);
    Pawn->GetWorld()->LineTraceSingleByChannel(LeftHit, TraceStart, TraceEnd, ECC_Visibility);

    TraceStart = RightFootLoc + FVector(0, 0, 50.f);
    TraceEnd = RightFootLoc - FVector(0, 0, 100.f);
    Pawn->GetWorld()->LineTraceSingleByChannel(RightHit, TraceStart, TraceEnd, ECC_Visibility);

    // Set IK targets (used by Two Bone IK nodes in AnimGraph)
    LeftFootIKTarget = LeftHit.bBlockingHit ? LeftHit.ImpactPoint : LeftFootLoc;
    RightFootIKTarget = RightHit.bBlockingHit ? RightHit.ImpactPoint : RightFootLoc;

    // Smooth the IK blend
    IKAlpha = FMath::FInterpTo(IKAlpha, Pawn->GetVelocity().Size() < 10.f ? 1.f : 0.f, DeltaSeconds, 10.f);
}

// Setup: Add UMotionWarpingComponent to your character
UPROPERTY(VisibleAnywhere)
UMotionWarpingComponent* MotionWarpComp;

AMyCharacter::AMyCharacter() {
    MotionWarpComp = CreateDefaultSubobject<UMotionWarpingComponent>(TEXT("MotionWarp"));
}

// Melee attack with lunge to target
void AMyCharacter::MeleeAttack(AActor* Target) {
    if (!Target || !AttackMontage) return;

    // Set warp target — character will reach this point during the montage
    FMotionWarpingTarget WarpTarget;
    WarpTarget.Name = TEXT("AttackTarget");
    WarpTarget.Location = Target->GetActorLocation();
    WarpTarget.Rotation = (Target->GetActorLocation() - GetActorLocation()).Rotation();
    MotionWarpComp->AddOrUpdateWarpTarget(WarpTarget);

    // Play the attack montage (which has a MotionWarping notify state
    // with WarpTargetName = "AttackTarget")
    PlayAnimMontage(AttackMontage);
}
